import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"APIs","description":"","frontmatter":{"uid":"9138f16a-3e33-440d-9133-98d6b5964d2a ... ..."},"headers":[],"relativePath":"10_core/40_service_apps/50_apis/portal_api.md","filePath":"10_core/40_service_apps/50_apis/portal_api.md"}'),i={name:"10_core/40_service_apps/50_apis/portal_api.md"};function o(r,e,l,c,p,d){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="apis" tabindex="-1">APIs <a class="header-anchor" href="#apis" aria-label="Permalink to &quot;APIs&quot;">​</a></h1><p>Current active doctrine centers on qiserver local runtime surfaces, QiAccess Start as the cognitive/operational front door, and Markdown/YAML files as the source of truth. Old cloud-hosted Supabase admin/app API assumptions below are retained as legacy/reference-only or future/conditional patterns.</p><h2 id="api-categories" tabindex="-1">API Categories <a class="header-anchor" href="#api-categories" aria-label="Permalink to &quot;API Categories&quot;">​</a></h2><p>QiOS has four distinct API categories. Each has a defined scope and must not cross into another&#39;s responsibility.</p><table tabindex="0"><thead><tr><th>Category</th><th>Scope</th><th>Location</th></tr></thead><tbody><tr><td><strong>Local Agent API</strong></td><td>Machine-local control — pipeline state, local config</td><td>Python (local machine)</td></tr><tr><td><strong>Hosted Admin API</strong></td><td>Fleet control — enrollment, dispatch, health</td><td>Future / conditional hosted layer</td></tr><tr><td><strong>App APIs</strong></td><td>Frontend interaction — route-safe reads/writes against approved services</td><td>QiAccess Start and future adapters</td></tr><tr><td><strong>Integration APIs</strong></td><td>External system connectors — future email, webhooks, Zapier</td><td>Local or future hosted connectors</td></tr><tr><td><strong>Worker APIs / Events</strong></td><td>Async job triggers and continuation signals</td><td>Local runtime first; future hosted queue optional</td></tr></tbody></table><h2 id="local-agent-api-machine-internal" tabindex="-1">Local Agent API (Machine-internal) <a class="header-anchor" href="#local-agent-api-machine-internal" aria-label="Permalink to &quot;Local Agent API (Machine-internal)&quot;">​</a></h2><p>The local Python API controls engine-side operations strictly for the node:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET  /status              -&gt; local agent health and pipeline state</span></span>
<span class="line"><span>GET  /watchers            -&gt; return current active filesystem assigned paths</span></span>
<span class="line"><span>POST /scan                -&gt; trigger a directory scan</span></span>
<span class="line"><span>POST /ingest              -&gt; manually push a single file</span></span>
<span class="line"><span>POST /job/execute         -&gt; accept and execute a dispatched command</span></span>
<span class="line"><span>POST /update              -&gt; receive configuration updates</span></span>
<span class="line"><span>GET  /health              -&gt; basic node liveness check</span></span></code></pre></div><h2 id="hosted-fleet-admin-api-server-side-future-conditional" tabindex="-1">Hosted Fleet / Admin API (Server-side, Future / Conditional) <a class="header-anchor" href="#hosted-fleet-admin-api-server-side-future-conditional" aria-label="Permalink to &quot;Hosted Fleet / Admin API (Server-side, Future / Conditional)&quot;">​</a></h2><p>The Cloud-hosted orchestration surface commands the fleet:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /fleet/enroll        -&gt; enroll a new machine device</span></span>
<span class="line"><span>POST /fleet/assign        -&gt; map a watch folder to a device node</span></span>
<span class="line"><span>POST /fleet/tokens        -&gt; issue or revoke access credentials</span></span>
<span class="line"><span>PUT  /fleet/config        -&gt; push configurations downward</span></span>
<span class="line"><span>POST /fleet/jobs          -&gt; queue execution task for a node</span></span>
<span class="line"><span>GET  /fleet/heartbeats    -&gt; fetch liveness matrix of devices</span></span>
<span class="line"><span>GET  /fleet/audit         -&gt; view action history for operations</span></span></code></pre></div><h2 id="app-api-responsibilities" tabindex="-1">App API Responsibilities <a class="header-anchor" href="#app-api-responsibilities" aria-label="Permalink to &quot;App API Responsibilities&quot;">​</a></h2><p>App APIs must:</p><ul><li>Respect current source-of-truth boundaries in Markdown/YAML docs and approved runtime services</li><li>Treat tenant-scoped Supabase JWT patterns as legacy/future only unless a specific job requires them</li><li>Avoid cross-boundary reads/writes that bypass the owning domain or pipeline</li><li>Never accept writes that bypass the pipeline (no raw archive inserts from frontend)</li></ul><h2 id="worker-events-contract" tabindex="-1">Worker Events Contract <a class="header-anchor" href="#worker-events-contract" aria-label="Permalink to &quot;Worker Events Contract&quot;">​</a></h2><p>Each async worker must define:</p><ul><li><strong>Input</strong>: what payload it receives (always includes a canonical ID)</li><li><strong>Output</strong>: what it writes back (always references the same canonical ID)</li><li><strong>Failure handling</strong>: retryable error state written to <code>qisys.jobs</code></li></ul><h2 id="api-law" tabindex="-1">API Law <a class="header-anchor" href="#api-law" aria-label="Permalink to &quot;API Law&quot;">​</a></h2><blockquote><p>No frontend or integration API may write directly to <code>qiarchive</code> records without going through the pipeline. The pipeline owns archive record state.</p></blockquote>`,19)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
